query:
CREATE TABLE `client_tokens` (`id` int AUTO_INCREMENT NOT NULL, `projectId` int NOT NULL, `token` varchar(128) NOT NULL, `createdAt` timestamp NOT NULL DEFAULT (now()), `expiresAt` timestamp NULL, `lastAccessedAt` timestamp NULL, CONSTRAINT `client_tokens_id` PRIMARY KEY(`id`), CONSTRAINT `client_tokens_token_unique` UNIQUE(`token`));
CREATE TABLE `inclusion_sections` (`id` int AUTO_INCREMENT NOT NULL, `projectId` int NOT NULL, `title` varchar(256) NOT NULL, `description` text, `imageUrl` text, `position` int NOT NULL DEFAULT 0, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `inclusion_sections_id` PRIMARY KEY(`id`));
CREATE TABLE `change_requests` (`id` int AUTO_INCREMENT NOT NULL, `projectId` int NOT NULL, `clientToken` varchar(128) NOT NULL, `category` varchar(128) NOT NULL, `description` text NOT NULL, `status` enum('pending','reviewed','actioned') NOT NULL DEFAULT 'pending', `adminNotes` text, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `change_requests_id` PRIMARY KEY(`id`));
CREATE TABLE `client_files` (`id` int AUTO_INCREMENT NOT NULL, `projectId` int NOT NULL, `clientToken` varchar(128) NOT NULL, `fileName` varchar(512) NOT NULL, `fileUrl` text NOT NULL, `fileKey` varchar(512) NOT NULL, `mimeType` varchar(128), `fileSizeBytes` int, `uploadedAt` timestamp NOT NULL DEFAULT (now()), CONSTRAINT `client_files_id` PRIMARY KEY(`id`))

